let _logoIOL = null, _logoLeisure = null;
function getLogoIOL() {
  return new Promise(res => {
    if (_logoIOL) { res(_logoIOL); return; }
    const i = new Image(); i.onload=()=>{_logoIOL=i;res(i);}; i.onerror=()=>res(null); i.src=LOGO_IOL_B64;
  });
}
function getLogoLeisure() {
  return new Promise(res => {
    if (_logoLeisure) { res(_logoLeisure); return; }
    const i = new Image(); i.onload=()=>{_logoLeisure=i;res(i);}; i.onerror=()=>res(null); i.src=LOGO_LEISURE_B64;
  });
}

