/* ════════════════════════════════════════════
   FEED
   ════════════════════════════════════════════ */
async function loadStories(refresh) {
  const grid=$id('stories-grid'), status=$id('feed-status'), btn=$id('refresh-btn');
  if(btn)btn.classList.add('spin');
  if(refresh)visible=PAGE_SZ;
  if(grid)grid.innerHTML='<div class="grid-loading"><div class="spinner"></div><p>Loading latest IOL stories…</p></div>';
  try {
    const res=await fetch(WORKER+'/all',{signal:AbortSignal.timeout(12000)});
    const data=await res.json();
    if(!data.ok||!data.stories||data.stories.length<3)throw new Error('empty');
    allStories=data.stories.map((s,i)=>({id:'live-'+i,cat:s.category||'news',headline:s.headline,excerpt:s.excerpt||'',source:s.source||'IOL',time:relTime(s.pubDate),url:s.url||'https://www.iol.co.za',image:s.image||''}));
    if(status){status.textContent=allStories.length+' stories · live';status.className='feed-status';}
  } catch(_) {
    allStories=[...PRELOADED];
    if(status){status.textContent=allStories.length+' stories · cached';status.className='feed-status';}
  }
  renderFeed();
  loadDoneFromSupabase();
  if(btn)btn.classList.remove('spin');
}

function renderFeed() {
  const grid=$id('stories-grid'); if(!grid)return;
  const filt=curFilter==='all'?allStories:allStories.filter(s=>{
    if(curFilter==='leisure')return['entertainment','lifestyle','leisure'].includes(s.cat);
    return s.cat===curFilter;
  });
  const vis=filt.slice(0,visible);
  if(!vis.length){grid.innerHTML='<div class="grid-loading"><p>No stories in this category.</p></div>';if($id('load-more-row'))$id('load-more-row').style.display='none';return;}
  grid.innerHTML=vis.map(s=>`
    <div class="scard${doneIds.has(s.id)?' done':''}" data-id="${esc(s.id)}">
      <div class="scard-cat">${esc(['entertainment','lifestyle'].includes(s.cat)?'Leisure':s.cat)}</div>
      <div class="scard-hl">${esc(s.headline)}</div>
      ${s.excerpt?`<div class="scard-ex">${esc(s.excerpt)}</div>`:''}
      <div class="scard-meta">
        <span class="scard-src">${esc(s.source)}</span><span>·</span><span>${esc(s.time)}</span>
        <span class="scard-cta">Make card →</span>
      </div>
    </div>`).join('');
  grid.querySelectorAll('.scard').forEach(c=>{c.addEventListener('click',()=>{const s=allStories.find(x=>x.id===c.dataset.id);if(s)openDesigner(s);});});
  const lmr=$id('load-more-row');if(lmr)lmr.style.display=filt.length>visible?'block':'none';
}

$id('cat-pills')?.addEventListener('click',e=>{const p=e.target.closest('.cpill');if(!p)return;document.querySelectorAll('.cpill').forEach(x=>x.classList.remove('active'));p.classList.add('active');curFilter=p.dataset.cat;visible=PAGE_SZ;renderFeed();});
$id('load-more-btn')?.addEventListener('click',()=>{visible+=PAGE_SZ;renderFeed();});
$id('refresh-btn')?.addEventListener('click',()=>loadStories(true));

/* ════════════════════════════════════════════
   DESIGNER OPEN/CLOSE
   ════════════════════════════════════════════ */
async function openDesigner(story) {
  d.cat=story.cat||'news'; d.kicker=autoKicker(story.headline,story.cat);
  d.headline=story.headline||''; d.imgUrl=story.image||'';
  d.storyUrl=story.url||''; d.shortUrl='';
  d.sqImgX=0;d.sqImgY=0;d.sqImgScale=1;
  d.reelImgX=0;d.reelImgY=0;d.reelImgScale=1;
  d.textPos='mid'; d.reelTextPos='mid';
  d.type='single'; d.slides=[]; d.slide=0; d.imgEl=null; d.storyId=story.id;
  d.headlineColor='#FFFFFF'; d.kickerColor='#FFFFFF';

  sv('ctrl-cat',d.cat); sv('ctrl-kicker',d.kicker); sv('ctrl-headline',d.headline);
  sv('ctrl-imgurl',d.imgUrl);
  document.querySelectorAll('.tt-btn').forEach(b=>b.classList.toggle('active',b.dataset.type==='single'));
  document.querySelectorAll('#pos-grid .pos-btn').forEach(b=>b.classList.toggle('active',b.dataset.pos==='mid'));
  document.querySelectorAll('#reel-pos-grid .pos-btn').forEach(b=>b.classList.toggle('active',b.dataset.pos==='mid'));
  // Sync colour pickers
  sv('ctrl-hl-color','#FFFFFF'); sv('ctrl-kicker-color','#FFFFFF');
  if($id('dnav-title'))$id('dnav-title').textContent=story.headline;
  updateCarouselUI(); buildShareText();

  $id('designer').classList.add('open');
  document.body.style.overflow='hidden';

  await waitPoppins();
  renderBoth();

  if(d.imgUrl){
    const proxy=WORKER+'/image?url='+encodeURIComponent(d.imgUrl);
    d.imgEl=await loadImgCORS(proxy);
    if(!d.imgEl)d.imgEl=await loadImgDirect(d.imgUrl);
    renderBoth();
  }
  if(d.storyUrl){
    try{const r=await fetch(WORKER+'/shorten?url='+encodeURIComponent(d.storyUrl));const j=await r.json();if(j.ok&&j.short){d.shortUrl=j.short;buildShareText();}}catch(_){}
  }
}

$id('back-btn')?.addEventListener('click',()=>{$id('designer').classList.remove('open');document.body.style.overflow='';renderFeed();});
function autoKicker(h,c){if(!h)return catCfg(c).lbl;return h.split(' ').slice(0,3).join(' ').toUpperCase();}

/* ════════════════════════════════════════════
   DESIGNER CONTROLS
   ════════════════════════════════════════════ */
function curSlide(){return d.type==='carousel'&&d.slides.length>0?d.slides[d.slide]:d;}

['ctrl-kicker','ctrl-headline','ctrl-cat'].forEach(id=>{
  $id(id)?.addEventListener('input',function(){
    const sl=curSlide();
    if(id==='ctrl-kicker'){d.kicker=this.value;sl.kicker=this.value;}
    if(id==='ctrl-headline'){d.headline=this.value;sl.headline=this.value;}
    if(id==='ctrl-cat'){d.cat=this.value;if(sl!==d)sl.cat=this.value;}
    renderBoth();
  });
});

// Colour pickers — sync visible swatch colour
$id('ctrl-hl-color')?.addEventListener('input',function(){
  const sw=$id('hl-swatch');if(sw)sw.style.background=this.value;
  d.headlineColor=this.value;const sl=curSlide();sl.headlineColor=this.value;renderBoth();
});
$id('ctrl-kicker-color')?.addEventListener('input',function(){
  const sw=$id('kicker-swatch');if(sw)sw.style.background=this.value;
  d.kickerColor=this.value;const sl=curSlide();sl.kickerColor=this.value;renderBoth();
});

$id('ctrl-imgurl')?.addEventListener('change',reloadImg);
$id('ctrl-reload')?.addEventListener('click',reloadImg);
async function reloadImg(){
  const url=gv('ctrl-imgurl').trim();d.imgUrl=url;d.imgX=0;d.imgY=0;d.imgScale=1;d.imgEl=null;
  if(url){d.imgEl=await loadImgCORS(WORKER+'/image?url='+encodeURIComponent(url));if(!d.imgEl)d.imgEl=await loadImgDirect(url);}
  const sl=curSlide();if(sl!==d){sl.imgUrl=url;sl.imgEl=d.imgEl;sl.sqImgX=0;sl.sqImgY=0;sl.sqImgScale=1;sl.reelImgX=0;sl.reelImgY=0;sl.reelImgScale=1;}
  renderBoth();
}

$id('pos-grid')?.addEventListener('click',e=>{
  const b=e.target.closest('.pos-btn');if(!b)return;
  $id('pos-grid').querySelectorAll('.pos-btn').forEach(x=>x.classList.remove('active'));
  b.classList.add('active'); d.textPos=b.dataset.pos; renderBoth();
});
$id('reel-pos-grid')?.addEventListener('click',e=>{
  const b=e.target.closest('.pos-btn');if(!b)return;
  $id('reel-pos-grid').querySelectorAll('.pos-btn').forEach(x=>x.classList.remove('active'));
  b.classList.add('active'); d.reelTextPos=b.dataset.pos; renderBoth();
});

$id('type-toggle')?.addEventListener('click',e=>{
  const b=e.target.closest('.tt-btn');if(!b)return;
  document.querySelectorAll('.tt-btn').forEach(x=>x.classList.remove('active'));b.classList.add('active');
  d.type=b.dataset.type;
  if(d.type==='carousel'&&d.slides.length===0)addSlide();
  $id('btn-dl-all').style.display=d.type==='carousel'?'inline-block':'none';
  updateCarouselUI();renderBoth();
});

function addSlide(){d.slides.push({kicker:d.kicker,headline:d.headline,cat:d.cat,headlineColor:d.headlineColor,kickerColor:d.kickerColor,imgUrl:d.imgUrl,imgEl:d.imgEl,sqImgX:0,sqImgY:0,sqImgScale:1,reelImgX:0,reelImgY:0,reelImgScale:1});d.slide=d.slides.length-1;}
function syncSlideUI(){const sl=d.slides[d.slide];if(!sl)return;sv('ctrl-kicker',sl.kicker);sv('ctrl-headline',sl.headline);sv('ctrl-cat',sl.cat||d.cat);sv('ctrl-imgurl',sl.imgUrl||'');sv('ctrl-hl-color',sl.headlineColor||'#FFFFFF');sv('ctrl-kicker-color',sl.kickerColor||'#FFFFFF');}
function updateCarouselUI(){const bar=$id('carousel-bar'),ind=$id('c-indicator'),isC=d.type==='carousel';if(bar)bar.style.display=isC?'flex':'none';if(ind)ind.textContent=isC?`Slide ${d.slide+1} / ${d.slides.length}`:'';;}

$id('c-add')?.addEventListener('click',()=>{addSlide();updateCarouselUI();renderBoth();});
$id('c-del')?.addEventListener('click',()=>{if(d.slides.length<=1)return;d.slides.splice(d.slide,1);d.slide=Math.min(d.slide,d.slides.length-1);syncSlideUI();updateCarouselUI();renderBoth();});
$id('c-prev')?.addEventListener('click',()=>{if(d.slide>0){d.slide--;syncSlideUI();updateCarouselUI();renderBoth();}});
$id('c-next')?.addEventListener('click',()=>{if(d.slide<d.slides.length-1){d.slide++;syncSlideUI();updateCarouselUI();renderBoth();}});

/* Image toolbar — applies to BOTH canvases simultaneously */
$id('itb-zoom-in')?.addEventListener('click',()=>{const sl=curSlide();sl.sqImgScale=Math.min(3,(sl.sqImgScale||1)+0.1);sl.reelImgScale=Math.min(3,(sl.reelImgScale||1)+0.1);if(sl!==d){d.sqImgScale=sl.sqImgScale;d.reelImgScale=sl.reelImgScale;}renderBoth();});
$id('itb-zoom-out')?.addEventListener('click',()=>{const sl=curSlide();sl.sqImgScale=Math.max(0.2,(sl.sqImgScale||1)-0.1);sl.reelImgScale=Math.max(0.2,(sl.reelImgScale||1)-0.1);if(sl!==d){d.sqImgScale=sl.sqImgScale;d.reelImgScale=sl.reelImgScale;}renderBoth();});
$id('itb-reset')?.addEventListener('click',()=>{const sl=curSlide();sl.sqImgX=0;sl.sqImgY=0;sl.sqImgScale=1;sl.reelImgX=0;sl.reelImgY=0;sl.reelImgScale=1;if(sl!==d){d.sqImgX=0;d.sqImgY=0;d.sqImgScale=1;d.reelImgX=0;d.reelImgY=0;d.reelImgScale=1;}renderBoth();});

/* Drag on SQUARE canvas */
const canvasSq=$id('card-canvas-sq');
if(canvasSq){
  canvasSq.addEventListener('mousedown',e=>{d.dragging=true;d.draggingTarget='sq';d.dsx=e.clientX;d.dsy=e.clientY;const sl=curSlide();d.dox=sl.sqImgX||0;d.doy=sl.sqImgY||0;e.preventDefault();});
  window.addEventListener('mousemove',e=>{if(!d.dragging)return;const target=d.draggingTarget;const sl=curSlide();if(target==='sq'){const r=canvasSq.getBoundingClientRect(),sx=SQ/r.width;sl.sqImgX=d.dox+(e.clientX-d.dsx)*sx;sl.sqImgY=d.doy+(e.clientY-d.dsy)*sx;if(sl!==d){d.sqImgX=sl.sqImgX;d.sqImgY=sl.sqImgY;}}else{const r=canvasReel.getBoundingClientRect(),sx=RW/r.width;sl.reelImgX=d.dox+(e.clientX-d.dsx)*sx;sl.reelImgY=d.doy+(e.clientY-d.dsy)*sx;if(sl!==d){d.reelImgX=sl.reelImgX;d.reelImgY=sl.reelImgY;}}renderBoth();});
  window.addEventListener('mouseup',()=>{d.dragging=false;});
  canvasSq.addEventListener('wheel',e=>{e.preventDefault();const sl=curSlide();sl.sqImgScale=Math.max(0.2,Math.min(3,(sl.sqImgScale||1)-e.deltaY*0.001));if(sl!==d)d.sqImgScale=sl.sqImgScale;renderBoth();},{passive:false});
}
/* Drag on REEL canvas */
const canvasReel=$id('card-canvas-reel');
if(canvasReel){
  canvasReel.addEventListener('mousedown',e=>{d.dragging=true;d.draggingTarget='reel';d.dsx=e.clientX;d.dsy=e.clientY;const sl=curSlide();d.dox=sl.reelImgX||0;d.doy=sl.reelImgY||0;e.preventDefault();});
  canvasReel.addEventListener('wheel',e=>{e.preventDefault();const sl=curSlide();sl.reelImgScale=Math.max(0.2,Math.min(3,(sl.reelImgScale||1)-e.deltaY*0.001));if(sl!==d)d.reelImgScale=sl.reelImgScale;renderBoth();},{passive:false});
}

/* Downloads */
$id('btn-dl-sq')?.addEventListener('click',()=>{markDone();dlCanvas('card-canvas-sq','iol-card-square.png');});
$id('btn-dl-reel')?.addEventListener('click',()=>{markDone();dlCanvas('card-canvas-reel','iol-card-reel.png');});
$id('btn-dl-all')?.addEventListener('click',async()=>{
  markDone();
  if(d.type!=='carousel'||!d.slides.length){dlCanvas('card-canvas-sq','iol-card-square.png');dlCanvas('card-canvas-reel','iol-card-reel.png');return;}
  for(let i=0;i<d.slides.length;i++){d.slide=i;syncSlideUI();updateCarouselUI();await renderBoth();dlCanvas('card-canvas-sq','iol-sq-'+String(i+1).padStart(2,'0')+'.png');dlCanvas('card-canvas-reel','iol-reel-'+String(i+1).padStart(2,'0')+'.png');await new Promise(r=>setTimeout(r,250));}
});
function markDone(){if(d.storyId){markDoneInSupabase(d.storyId,d.headline);renderFeed();}}
function dlCanvas(canvasId,fn){const c=$id(canvasId);if(!c)return;try{const a=document.createElement('a');a.href=c.toDataURL('image/png');a.download=fn;a.click();}catch(e){alert('Right-click the card and choose "Save image as".');}}

/* Share text */
$id('copy-share-btn')?.addEventListener('click',function(){const t=gv('ctrl-share');if(!t)return;navigator.clipboard.writeText(t).then(()=>{const o=this.textContent;this.textContent='Copied!';setTimeout(()=>this.textContent=o,1600);});});
function buildShareText(){
  const cc=catCfg(d.cat);
  const tagMap={news:'#SouthAfrica #NewsZA #IOL',politics:'#SAPoltics #SouthAfrica #IOL',sport:'#SportZA #SouthAfrica #IOL',business:'#BusinessZA #SouthAfrica #IOL',technology:'#TechZA #SouthAfrica #IOL',entertainment:'#Leisure #Entertainment #IOL',lifestyle:'#Leisure #Lifestyle #IOL',motoring:'#Motoring #SouthAfrica #IOL',travel:'#Travel #SouthAfrica #IOL'};
  const tags=tagMap[d.cat]||'#SouthAfrica #IOL';
  const url=d.shortUrl||d.storyUrl;
  const urlLine=url?'\n\n\uD83D\uDD17 '+url:'';
  const follow=cc.style==='leisure'?'Follow @IOLLeisure for entertainment and lifestyle news':'Follow @IOL for the latest South African news';
  sv('ctrl-share',d.headline+urlLine+'\n\n'+tags+'\n\n\uD83D\uDCF0 '+follow);
}

/* ════════════════════════════════════════════
   RENDER BOTH CARDS
   ════════════════════════════════════════════ */
async function renderBoth() {
  const [logoIOL, logoLeisure] = await Promise.all([getLogoIOL(), getLogoLeisure()]);
  const sl = curSlide();
  const p = {
    kicker:        sl.kicker        || d.kicker        || '',
    headline:      sl.headline      || d.headline       || '',
    headlineColor: sl.headlineColor || d.headlineColor  || '#FFFFFF',
    kickerColor:   sl.kickerColor   || d.kickerColor    || '#FFFFFF',
    cat:           sl.cat           || d.cat            || 'news',
    imgEl:         sl.imgEl         || d.imgEl,
    sqImgX:     sl.sqImgX   != null ? sl.sqImgX   : d.sqImgX,
    sqImgY:     sl.sqImgY   != null ? sl.sqImgY   : d.sqImgY,
    sqImgScale: sl.sqImgScale       || d.sqImgScale     || 1,
    reelImgX:   sl.reelImgX != null ? sl.reelImgX : d.reelImgX,
    reelImgY:   sl.reelImgY != null ? sl.reelImgY : d.reelImgY,
    reelImgScale:sl.reelImgScale    || d.reelImgScale   || 1,
    textPos:    d.textPos    || 'mid',
    reelTextPos: d.reelTextPos || 'mid',
    logoIOL, logoLeisure,
  };
  const cc = catCfg(p.cat);

  // Square 1080x1080
  const csq = $id('card-canvas-sq');
  if (csq) {
    csq.width=SQ; csq.height=SQ;
    const ctx=csq.getContext('2d');
    if(cc.style==='leisure') drawLeisureSq(ctx,p,cc);
    else drawStandardSq(ctx,p,cc);
  }

  // Reel 1080x1920
  const creel = $id('card-canvas-reel');
  if (creel) {
    creel.width=RW; creel.height=RH;
    const ctx=creel.getContext('2d');
    if(cc.style==='leisure') drawLeisureReel(ctx,p,cc);
    else drawStandardReel(ctx,p,cc);
  }
}

/* ════════════════════════════════════════════
   DRAW: STANDARD SQUARE
   ════════════════════════════════════════════ */
function drawStandardSq(ctx, p, cc) {
  const W=SQ, H=SQ;
  drawPhotoAndOverlay(ctx, p, W, H, p.sqImgX, p.sqImgY, p.sqImgScale);

  // Left accent strip
  ctx.fillStyle=cc.col; ctx.fillRect(0,0,6,H);

  // Kicker box top-left
  drawKickerBox(ctx, p.kicker, p.kickerColor, 48, 52, W-96);

  // Text block
  const logoZone=110;
  drawTextBlock(ctx, p.headline, null, p.headlineColor, W, H, logoZone, p.textPos, 60, W-96);

  // IOL logo + pill
  drawIOLBadge(ctx, p.logoIOL, cc, W/2, H-112, 68, 52);
}

/* ════════════════════════════════════════════
   DRAW: STANDARD REEL (1080x1920)
   ════════════════════════════════════════════ */
function drawStandardReel(ctx, p, cc) {
  const W=RW, H=RH;
  drawPhotoAndOverlay(ctx, p, W, H, p.reelImgX, p.reelImgY, p.reelImgScale);

  // Left accent strip
  ctx.fillStyle=cc.col; ctx.fillRect(0,0,6,H);

  // Kicker box top-left (slightly bigger on tall format)
  drawKickerBox(ctx, p.kicker, p.kickerColor, 52, 80, W-104);

  // Text block — centred in the lower 2/3
  const logoZone=130;
  const blockAreaTop = H*0.38, blockAreaH = H - blockAreaTop - logoZone;
  ctx.save();
  ctx.font='800 72px Poppins,Arial Black,sans-serif'; ctx.textAlign='center'; ctx.textBaseline='alphabetic';
  const hlLines=wrapText(ctx,p.headline||'',W-100), hlLH=86;
  const totalH=hlLines.length*hlLH;
  let blockTop;
  const rp = p.reelTextPos||'mid';
  if(rp==='top')      blockTop=blockAreaTop+60;
  else if(rp==='bot') blockTop=blockAreaTop+blockAreaH-totalH-20;
  else                blockTop=blockAreaTop+(blockAreaH-totalH)/2;
  ctx.fillStyle=p.headlineColor||'#FFFFFF';
  hlLines.forEach((ln,i)=>ctx.fillText(ln,W/2,blockTop+(i+1)*hlLH));
  ctx.restore();

  // IOL logo + pill — top RIGHT (reel format)
  drawIOLBadge(ctx, p.logoIOL, cc, W-100, 60, 88, 67);
}

/* ════════════════════════════════════════════
   DRAW: LEISURE SQUARE
   ════════════════════════════════════════════ */
function drawLeisureSq(ctx, p, cc) {
  const W=SQ, H=SQ;
  // Dark mauve/purple background
  ctx.fillStyle='#1A0E18'; ctx.fillRect(0,0,W,H);

  // Photo
  drawPhoto(ctx, p, W, H, p.sqImgX, p.sqImgY, p.sqImgScale);

  // Heavy purple-tinted gradient bottom half
  const g=ctx.createLinearGradient(0,0,0,H);
  g.addColorStop(0,'rgba(20,8,18,0)'); g.addColorStop(0.3,'rgba(20,8,18,0.28)');
  g.addColorStop(0.52,'rgba(20,8,18,0.78)'); g.addColorStop(1,'rgba(20,8,18,0.97)');
  ctx.fillStyle=g; ctx.fillRect(0,0,W,H);

  // IOL Leisure logo top-left
  drawLeisureLogo(ctx, p.logoLeisure, 44, 36, 190, 134);

  // Headline (hot pink, bold, left-aligned, large)
  const padL=52, maxW=W-padL-48;
  const textY=p.textPos==='top'?260:p.textPos==='bot'?520:390;
  ctx.save();
  ctx.font='900 68px Poppins,Arial Black,sans-serif'; ctx.textAlign='left'; ctx.textBaseline='alphabetic';
  ctx.fillStyle=p.headlineColor||'#F06BB5';
  const hlLines=wrapText(ctx,p.headline||'',maxW), hlLH=80;
  hlLines.forEach((ln,i)=>ctx.fillText(ln,padL,textY+(i+1)*hlLH));
  // Rule line below headline
  const ruleY=textY+hlLines.length*hlLH+20;
  ctx.strokeStyle='rgba(255,255,255,0.7)'; ctx.lineWidth=2.5;
  ctx.beginPath(); ctx.moveTo(padL,ruleY); ctx.lineTo(padL+220,ruleY); ctx.stroke();
  ctx.restore();
}

/* ════════════════════════════════════════════
   DRAW: LEISURE REEL (1080x1920)
   ════════════════════════════════════════════ */
function drawLeisureReel(ctx, p, cc) {
  const W=RW, H=RH;
  ctx.fillStyle='#1A0E18'; ctx.fillRect(0,0,W,H);
  drawPhoto(ctx, p, W, H, p.reelImgX, p.reelImgY, p.reelImgScale);

  const g=ctx.createLinearGradient(0,0,0,H);
  g.addColorStop(0,'rgba(20,8,18,0)'); g.addColorStop(0.25,'rgba(20,8,18,0.20)');
  g.addColorStop(0.5,'rgba(20,8,18,0.72)'); g.addColorStop(1,'rgba(20,8,18,0.97)');
  ctx.fillStyle=g; ctx.fillRect(0,0,W,H);

  // IOL Leisure logo top-right (bigger on tall format)
  drawLeisureLogo(ctx, p.logoLeisure, W-278, 48, 230, 163);

  // Headline
  const padL=56, maxW=W-padL-56;
  const rp2=p.reelTextPos||'mid';const textY=rp2==='top'?420:rp2==='bot'?1100:760;
  ctx.save();
  ctx.font='900 80px Poppins,Arial Black,sans-serif'; ctx.textAlign='left'; ctx.textBaseline='alphabetic';
  ctx.fillStyle=p.headlineColor||'#F06BB5';
  const hlLines=wrapText(ctx,p.headline||'',maxW), hlLH=96;
  hlLines.forEach((ln,i)=>ctx.fillText(ln,padL,textY+(i+1)*hlLH));
  const ruleY=textY+hlLines.length*hlLH+24;
  ctx.strokeStyle='rgba(255,255,255,0.7)'; ctx.lineWidth=3;
  ctx.beginPath(); ctx.moveTo(padL,ruleY); ctx.lineTo(padL+260,ruleY); ctx.stroke();
  ctx.restore();
}

/* ════════════════════════════════════════════
   SHARED DRAW HELPERS
   ════════════════════════════════════════════ */
function drawPhotoAndOverlay(ctx, p, W, H, imgX, imgY, imgScale) {
  ctx.fillStyle='#0D0D0D'; ctx.fillRect(0,0,W,H);
  drawPhoto(ctx, p, W, H, imgX, imgY, imgScale);
  const g=ctx.createLinearGradient(0,0,0,H);
  g.addColorStop(0,'rgba(0,0,0,0.15)'); g.addColorStop(0.38,'rgba(0,0,0,0.40)');
  g.addColorStop(0.65,'rgba(0,0,0,0.60)'); g.addColorStop(1,'rgba(0,0,0,0.84)');
  ctx.fillStyle=g; ctx.fillRect(0,0,W,H);
}

function drawPhoto(ctx, p, W, H, imgX, imgY, imgScale) {
  if(!p.imgEl) return;
  ctx.save(); ctx.beginPath(); ctx.rect(0,0,W,H); ctx.clip();
  const sc=Math.max(W/p.imgEl.width,H/p.imgEl.height)*(imgScale||1);
  ctx.drawImage(p.imgEl,(W-p.imgEl.width*sc)/2+(imgX||0),(H-p.imgEl.height*sc)/2+(imgY||0),p.imgEl.width*sc,p.imgEl.height*sc);
  ctx.restore();
}

function drawKickerBox(ctx, kicker, color, kx, ky, maxW) {
  ctx.save();
  ctx.font='800 30px Poppins,Arial Black,sans-serif'; ctx.textBaseline='middle';
  const kt=(kicker||'').toUpperCase(), kw=Math.min(ctx.measureText(kt).width+40, maxW), kh=52;
  ctx.fillStyle='rgba(0,0,0,0.22)'; ctx.fillRect(kx,ky,kw,kh);
  ctx.strokeStyle='rgba(255,255,255,0.75)'; ctx.lineWidth=2; ctx.strokeRect(kx,ky,kw,kh);
  ctx.fillStyle=color||'#FFFFFF'; ctx.fillText(kt,kx+20,ky+kh/2,kw-40);
  ctx.restore();
}

function drawTextBlock(ctx, headline, caption, headlineColor, W, H, logoZone, textPos, fontSize, maxW) {
  ctx.save();
  ctx.font=`800 ${fontSize}px Poppins,Arial Black,sans-serif`; ctx.textAlign='center'; ctx.textBaseline='alphabetic';
  const hlLines=wrapText(ctx,headline||'',maxW), hlLH=Math.round(fontSize*1.22);
  const totalH=hlLines.length*hlLH;
  const topY=190, botY=H-logoZone-totalH-40, midY=(H-logoZone-totalH)/2+24;
  const blockTop=textPos==='top'?topY:textPos==='bot'?botY:midY;
  ctx.fillStyle=headlineColor||'#FFFFFF';
  hlLines.forEach((ln,i)=>ctx.fillText(ln,W/2,blockTop+(i+1)*hlLH));
  ctx.restore();
}

function drawIOLBadge(ctx, logo, cc, cx, ly, lw, lh) {
  if(logo){
    ctx.drawImage(logo,Math.round(cx-lw/2),Math.round(ly),lw,lh);
  } else {
    ctx.save(); ctx.fillStyle=cc.col;
    ctx.beginPath(); ctx.moveTo(cx-lw/2+2,ly+4); ctx.lineTo(cx-lw/2+2,ly+lh-4); ctx.lineTo(cx-lw/2+lw*0.2,ly+4); ctx.closePath(); ctx.fill();
    ctx.font='900 '+Math.round(lh*0.6)+'px Poppins,sans-serif'; ctx.fillStyle='#fff'; ctx.textAlign='center'; ctx.textBaseline='top'; ctx.fillText('IOL',cx+lw*0.1,ly+4);
    ctx.restore();
  }
  ctx.save();
  ctx.font='700 '+Math.round(lh*0.3)+'px Poppins,Arial,sans-serif'; ctx.textAlign='center'; ctx.textBaseline='middle';
  const pw=ctx.measureText(cc.lbl).width+28, ph=Math.round(lh*0.48), py=ly+lh+5;
  ctx.fillStyle=cc.col; ctx.fillRect(cx-pw/2,py,pw,ph);
  ctx.fillStyle='#fff'; ctx.fillText(cc.lbl,cx,py+ph/2);
  ctx.restore();
}

function drawLeisureLogo(ctx, logo, x, y, w, h) {
  if(logo) { ctx.drawImage(logo,x,y,w,h); return; }
  // Fallback text
  ctx.save();
  ctx.font='italic 700 36px Georgia,serif'; ctx.fillStyle='#4ECBCB';
  ctx.textBaseline='top'; ctx.textAlign='left'; ctx.fillText('IOL Leisure',x,y);
  ctx.restore();
}

function wrapText(ctx,text,maxW){
  if(!text)return[];
  const words=text.split(' '),lines=[];let cur='';
  words.forEach(w=>{const t=cur?cur+' '+w:w;if(ctx.measureText(t).width<=maxW)cur=t;else{if(cur)lines.push(cur);cur=w;}});
  if(cur)lines.push(cur);return lines;
}

/* ════════════════════════════════════════════
   IMAGE LOADERS
   ════════════════════════════════════════════ */
function loadImgCORS(src){return new Promise(res=>{const i=new Image();i.crossOrigin='anonymous';i.onload=()=>res(i);i.onerror=()=>res(null);i.src=src;setTimeout(()=>res(null),10000);});}
function loadImgDirect(src){return new Promise(res=>{const i=new Image();i.onload=()=>res(i);i.onerror=()=>res(null);i.src=src;setTimeout(()=>res(null),8000);});}

